@namespace sv_276434a96f0941f2b607aec9daa7d0f5.Components.Pages.Settings
@using sv_276434a96f0941f2b607aec9daa7d0f5.Services

<div class="security-section">
    <h4>Security</h4>
    <p class="text-muted">Manage passwords, two-factor authentication, and sessions</p>
    <hr />

    <!-- Change Password Panel -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer;" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span class="fw-semibold">Change Password</span>
            <span>@(_passwordPanelOpen ? "Ō¢▓" : "Ō¢╝")</span>
        </div>
        @if (_passwordPanelOpen)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>

                @if (!string.IsNullOrEmpty(_passwordMessage))
                {
                    <div class="alert @(_passwordError ? "alert-danger" : "alert-success") py-2">
                        @_passwordMessage
                    </div>
                }

                <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @if (_changingPassword)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Update Password
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                @if (Security?.LastPasswordChange is not null)
                {
                    <small class="text-muted ms-2">
                        Last password change: @Security.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </small>
                }
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" @bind="TwoFactorEnabled" />
            </div>
        </div>
    </div>

    <!-- Active Sessions -->
    <div class="card mb-4">
        <div class="card-header fw-semibold">Active Sessions</div>
        <div class="card-body p-0">
            @if (Security?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in Security.Sessions)
                            {
                                var isCurrent = session.Id == Security.Sessions[0].Id;
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-primary ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
