@namespace sv_276434a96f0941f2b607aec9daa7d0f5.Components.Pages.Settings
@using sv_276434a96f0941f2b607aec9daa7d0f5.Services

<div class="appearance-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize the look and feel of the application</p>
    <hr />

    <div class="row">
        <div class="col-md-7">
            <!-- Theme -->
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")" value="@theme"
                               checked="@(Theme == theme)"
                               @onchange="() => Theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <!-- Font Size -->
            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")" value="@size"
                               checked="@(FontSize == size)"
                               @onchange="() => FontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <!-- Language -->
            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" style="max-width: 250px;"
                        @bind="Language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
                <small class="text-muted">Reduce spacing and padding for a denser layout.</small>
            </div>

            @if (!string.IsNullOrEmpty(_statusMessage))
            {
                <div class="alert alert-success alert-dismissible fade show" role="alert">
                    @_statusMessage
                    <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
                </div>
            }

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <!-- Live Preview -->
        <div class="col-md-5">
            <div class="preview-card card @GetPreviewThemeClass()" style="@GetPreviewStyle()">
                <div class="card-header fw-semibold">
                    Live Preview
                </div>
                <div class="card-body">
                    <h6 style="@GetPreviewFontStyle()">Sample Heading</h6>
                    <p style="@GetPreviewFontStyle()" class="@(CompactMode ? "mb-1" : "mb-3")">
                        This is how your content will look with the selected settings.
                    </p>
                    <div class="d-flex gap-2 @(CompactMode ? "flex-wrap" : "")">
                        <span class="badge bg-primary">Badge</span>
                        <span class="badge bg-secondary">Tag</span>
                    </div>
                    <hr class="@(CompactMode ? "my-1" : "my-3")" />
                    <small class="text-muted">Language: @Language</small>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;

    private string? _statusMessage;
    private bool _saving;

    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_saving)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }

    private string GetPreviewThemeClass() => Theme switch
    {
        "Dark" => "text-bg-dark",
        _ => ""
    };

    private string GetPreviewStyle()
    {
        var padding = CompactMode ? "0" : "inherit";
        return $"transition: all 0.3s ease;";
    }

    private string GetPreviewFontStyle() => FontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };
}

